/**
 * 遥测数据 Canvas 图表绘制工具
 * 纯 Canvas 2D 实现，无第三方依赖
 * 绘制速度-高度双轴曲线图 + 事件标记
 */

const COLORS = {
  bg: '#1c1c1e',
  grid: 'rgba(255,255,255,0.06)',
  axisLine: 'rgba(255,255,255,0.15)',
  axisText: 'rgba(255,255,255,0.45)',
  velocity: '#00d4ff',
  velocityFill: 'rgba(0,212,255,0.08)',
  altitude: '#ff6b35',
  altitudeFill: 'rgba(255,107,53,0.08)',
  event: 'rgba(255,255,255,0.5)',
  eventLine: 'rgba(255,255,255,0.12)',
  title: 'rgba(255,255,255,0.85)',
  legend: 'rgba(255,255,255,0.6)'
}

const EVENT_LABELS = {
  maxq: 'Max-Q',
  throttle_down_start: '节流开始',
  throttle_down_end: '节流结束',
  meco: 'MECO',
  ses1: 'SES-1',
  ses2: 'SES-2',
  seco: 'SECO',
  fairing_deploy: '整流罩分离',
  stage_sep: '级间分离',
  entry_burn_start: '再入点火',
  entry_burn_end: '再入结束',
  landing_burn_start: '着陆点火',
  landing: '着陆'
}

/**
 * 对遥测数据降采样，控制绘制点数
 */
function downsample(points, maxPoints = 200) {
  if (!points || points.length <= maxPoints) return points || []
  const step = points.length / maxPoints
  const result = []
  for (let i = 0; i < maxPoints; i++) {
    result.push(points[Math.floor(i * step)])
  }
  // 确保最后一个点
  if (result[result.length - 1] !== points[points.length - 1]) {
    result.push(points[points.length - 1])
  }
  return result
}

/**
 * 计算合适的刻度间隔
 */
function niceInterval(range, targetTicks = 5) {
  if (range <= 0) return 1
  const rough = range / targetTicks
  const mag = Math.pow(10, Math.floor(Math.log10(rough)))
  const residual = rough / mag
  let nice
  if (residual <= 1.5) nice = 1
  else if (residual <= 3) nice = 2
  else if (residual <= 7) nice = 5
  else nice = 10
  return nice * mag
}

/**
 * 绘制遥测图表
 * @param {CanvasRenderingContext2D} ctx Canvas 2D 上下文
 * @param {Object} telemetryData Launch Dashboard API 返回的数据
 * @param {Object} options 绘制选项
 * @param {Number} options.width Canvas 宽度（物理像素）
 * @param {Number} options.height Canvas 高度（物理像素）
 * @param {Number} options.dpr 设备像素比
 */
function drawTelemetryChart(ctx, telemetryData, options = {}) {
  const { width = 700, height = 400, dpr = 2 } = options
  const w = width
  const h = height

  // 边距
  const pad = { top: 50 * dpr, right: 65 * dpr, bottom: 45 * dpr, left: 60 * dpr }
  const plotW = w - pad.left - pad.right
  const plotH = h - pad.top - pad.bottom

  // 提取数据
  const raw = telemetryData.raw || telemetryData.analysed || []
  const stageData = Array.isArray(raw) ? raw[0] : raw
  const points = (stageData && stageData.telemetry) || []
  const events = telemetryData.events || []

  if (points.length === 0) return false

  const sampled = downsample(points, 250)

  // 计算数据范围
  let minT = Infinity, maxT = -Infinity
  let maxV = -Infinity, maxA = -Infinity
  for (const p of sampled) {
    if (p.time < minT) minT = p.time
    if (p.time > maxT) maxT = p.time
    if (p.velocity > maxV) maxV = p.velocity
    if (p.altitude > maxA) maxA = p.altitude
  }
  if (minT === Infinity) return false

  // 留 5% 余量
  maxV = maxV * 1.05 || 100
  maxA = maxA * 1.05 || 100

  // 坐标转换
  const toX = (t) => pad.left + ((t - minT) / (maxT - minT || 1)) * plotW
  const toYv = (v) => pad.top + plotH - (v / maxV) * plotH
  const toYa = (a) => pad.top + plotH - (a / maxA) * plotH

  // 清空画布
  ctx.fillStyle = COLORS.bg
  ctx.fillRect(0, 0, w, h)

  // 网格线
  const fontSize = 10 * dpr
  ctx.font = `${fontSize}px -apple-system, sans-serif`
  ctx.textBaseline = 'middle'

  // Y轴网格 - 速度（左）
  const vInterval = niceInterval(maxV, 5)
  ctx.strokeStyle = COLORS.grid
  ctx.lineWidth = 1
  for (let v = 0; v <= maxV; v += vInterval) {
    const y = toYv(v)
    ctx.beginPath()
    ctx.moveTo(pad.left, y)
    ctx.lineTo(w - pad.right, y)
    ctx.stroke()
    ctx.fillStyle = COLORS.velocity
    ctx.textAlign = 'right'
    ctx.fillText(v >= 1000 ? (v / 1000).toFixed(1) + 'k' : Math.round(v), pad.left - 6 * dpr, y)
  }

  // Y轴网格 - 高度（右）
  const aInterval = niceInterval(maxA, 5)
  for (let a = 0; a <= maxA; a += aInterval) {
    const y = toYa(a)
    ctx.fillStyle = COLORS.altitude
    ctx.textAlign = 'left'
    ctx.fillText(Math.round(a), w - pad.right + 6 * dpr, y)
  }

  // X轴刻度 - 时间
  const tInterval = niceInterval(maxT - minT, 6)
  ctx.fillStyle = COLORS.axisText
  ctx.textAlign = 'center'
  for (let t = Math.ceil(minT / tInterval) * tInterval; t <= maxT; t += tInterval) {
    const x = toX(t)
    const label = t >= 60 ? `${Math.floor(t / 60)}:${String(Math.round(t % 60)).padStart(2, '0')}` : `${Math.round(t)}s`
    ctx.fillText(label, x, h - pad.bottom + 18 * dpr)
    // 垂直网格
    ctx.strokeStyle = COLORS.grid
    ctx.beginPath()
    ctx.moveTo(x, pad.top)
    ctx.lineTo(x, pad.top + plotH)
    ctx.stroke()
  }

  // 绘制事件标记线
  for (const evt of events) {
    if (evt.time == null || evt.time < minT || evt.time > maxT) continue
    const x = toX(evt.time)
    ctx.strokeStyle = COLORS.eventLine
    ctx.lineWidth = 1
    ctx.setLineDash([4 * dpr, 4 * dpr])
    ctx.beginPath()
    ctx.moveTo(x, pad.top)
    ctx.lineTo(x, pad.top + plotH)
    ctx.stroke()
    ctx.setLineDash([])
    // 事件标签
    const label = EVENT_LABELS[evt.key] || evt.key
    if (label) {
      ctx.fillStyle = COLORS.event
      ctx.font = `${8 * dpr}px -apple-system, sans-serif`
      ctx.textAlign = 'center'
      ctx.save()
      ctx.translate(x, pad.top - 4 * dpr)
      ctx.rotate(-Math.PI / 6)
      ctx.fillText(label, 0, 0)
      ctx.restore()
      ctx.font = `${fontSize}px -apple-system, sans-serif`
    }
  }

  // 绘制速度曲线（带填充）
  ctx.lineWidth = 2 * dpr
  ctx.strokeStyle = COLORS.velocity
  ctx.beginPath()
  for (let i = 0; i < sampled.length; i++) {
    const x = toX(sampled[i].time)
    const y = toYv(sampled[i].velocity)
    if (i === 0) ctx.moveTo(x, y)
    else ctx.lineTo(x, y)
  }
  ctx.stroke()
  // 填充
  ctx.lineTo(toX(sampled[sampled.length - 1].time), pad.top + plotH)
  ctx.lineTo(toX(sampled[0].time), pad.top + plotH)
  ctx.closePath()
  ctx.fillStyle = COLORS.velocityFill
  ctx.fill()

  // 绘制高度曲线（带填充）
  ctx.strokeStyle = COLORS.altitude
  ctx.lineWidth = 2 * dpr
  ctx.beginPath()
  for (let i = 0; i < sampled.length; i++) {
    const x = toX(sampled[i].time)
    const y = toYa(sampled[i].altitude)
    if (i === 0) ctx.moveTo(x, y)
    else ctx.lineTo(x, y)
  }
  ctx.stroke()
  ctx.lineTo(toX(sampled[sampled.length - 1].time), pad.top + plotH)
  ctx.lineTo(toX(sampled[0].time), pad.top + plotH)
  ctx.closePath()
  ctx.fillStyle = COLORS.altitudeFill
  ctx.fill()

  // 坐标轴边框
  ctx.strokeStyle = COLORS.axisLine
  ctx.lineWidth = 1
  ctx.beginPath()
  ctx.moveTo(pad.left, pad.top)
  ctx.lineTo(pad.left, pad.top + plotH)
  ctx.lineTo(w - pad.right, pad.top + plotH)
  ctx.lineTo(w - pad.right, pad.top)
  ctx.stroke()

  // 图例
  const legendY = 20 * dpr
  const legendFontSize = 11 * dpr
  ctx.font = `bold ${legendFontSize}px -apple-system, sans-serif`

  // 速度图例
  ctx.fillStyle = COLORS.velocity
  ctx.fillRect(pad.left, legendY - 5 * dpr, 14 * dpr, 3 * dpr)
  ctx.fillStyle = COLORS.legend
  ctx.textAlign = 'left'
  ctx.fillText('速度 (km/h)', pad.left + 18 * dpr, legendY)

  // 高度图例
  const altLegendX = pad.left + 120 * dpr
  ctx.fillStyle = COLORS.altitude
  ctx.fillRect(altLegendX, legendY - 5 * dpr, 14 * dpr, 3 * dpr)
  ctx.fillStyle = COLORS.legend
  ctx.fillText('高度 (km)', altLegendX + 18 * dpr, legendY)

  // 轴标签
  ctx.font = `${9 * dpr}px -apple-system, sans-serif`
  ctx.fillStyle = COLORS.axisText
  ctx.textAlign = 'center'
  ctx.fillText('T+ 时间', pad.left + plotW / 2, h - 4 * dpr)

  return true
}

/**
 * 绘制飞行剖面图（类似 SpaceX 官网弧线轨迹图）
 * 用贝塞尔曲线绘制：发射→上升→级间分离→一级返回着陆 + 二级继续入轨
 * @param {CanvasRenderingContext2D} ctx
 * @param {Object} telemetryData 遥测数据（含 events）
 * @param {Object} options { width, height, dpr, hasLanding, landingType }
 */
function drawFlightProfile(ctx, telemetryData, options = {}) {
  const { width = 700, height = 500, dpr = 2, hasLanding = true, landingType = 'ASDS' } = options
  const w = width
  const h = height

  // 事件时间映射
  const events = (telemetryData && telemetryData.events) || []
  const eventMap = {}
  for (const e of events) {
    if (e.time != null) eventMap[e.key] = e.time
  }

  // 颜色
  const C = {
    bg: '#0d0d0f',
    trail: '#ffffff',
    trailGlow: 'rgba(255,255,255,0.15)',
    boosterTrail: 'rgba(255,255,255,0.5)',
    label: 'rgba(255,255,255,0.85)',
    sublabel: 'rgba(255,255,255,0.45)',
    dot: '#ffffff',
    dotGlow: 'rgba(0,212,255,0.4)',
    flame: '#ff6b35',
    flameGlow: 'rgba(255,107,53,0.3)',
    fairing: 'rgba(255,255,255,0.3)',
    ground: 'rgba(255,255,255,0.08)',
    groundLine: 'rgba(255,255,255,0.12)'
  }

  const pad = { top: 40 * dpr, right: 30 * dpr, bottom: 50 * dpr, left: 30 * dpr }
  const plotW = w - pad.left - pad.right
  const plotH = h - pad.top - pad.bottom

  // 清空
  ctx.fillStyle = C.bg
  ctx.fillRect(0, 0, w, h)

  // 地面线
  const groundY = pad.top + plotH
  ctx.strokeStyle = C.groundLine
  ctx.lineWidth = 1
  ctx.beginPath()
  ctx.moveTo(pad.left, groundY)
  ctx.lineTo(w - pad.right, groundY)
  ctx.stroke()

  // 地面渐变
  const groundGrad = ctx.createLinearGradient(0, groundY, 0, h)
  groundGrad.addColorStop(0, C.ground)
  groundGrad.addColorStop(1, 'transparent')
  ctx.fillStyle = groundGrad
  ctx.fillRect(pad.left, groundY, plotW, pad.bottom)

  // ===== 关键坐标点（归一化后映射到画布）=====
  // 发射弧线的关键节点
  const pts = {
    launch:    { x: 0.06, y: 1.0 },    // 发射点（地面）
    ascent:    { x: 0.18, y: 0.55 },   // 上升段中点
    maxq:      { x: 0.25, y: 0.38 },   // Max-Q
    meco:      { x: 0.38, y: 0.12 },   // MECO（主发动机关机）
    sep:       { x: 0.42, y: 0.08 },   // 级间分离
    flip:      { x: 0.46, y: 0.06 },   // 翻转机动
    fairing:   { x: 0.52, y: 0.04 },   // 整流罩分离
    // 二级继续
    s2coast:   { x: 0.65, y: 0.03 },   // 二级滑行
    seco:      { x: 0.85, y: 0.02 },   // 二级关机
    deploy:    { x: 0.95, y: 0.02 },   // 载荷部署
    // 一级返回
    gridFins:  { x: 0.52, y: 0.10 },   // 栅格翼展开
    entry:     { x: 0.58, y: 0.25 },   // 再入点火
    aero:      { x: 0.68, y: 0.50 },   // 气动制导
    landing:   { x: 0.78, y: 0.95 },   // 着陆点火
    landed:    { x: 0.82, y: 1.0 }     // 着陆
  }

  // 坐标转换
  const toCanvas = (p) => ({
    x: pad.left + p.x * plotW,
    y: pad.top + p.y * plotH
  })

  // 所有点转换
  const cp = {}
  for (const k in pts) cp[k] = toCanvas(pts[k])

  // ===== 绘制主飞行弧线（发射→MECO→级间分离→整流罩分离）=====
  // 发光效果
  ctx.strokeStyle = C.trailGlow
  ctx.lineWidth = 6 * dpr
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'
  ctx.beginPath()
  ctx.moveTo(cp.launch.x, cp.launch.y)
  ctx.quadraticCurveTo(
    cp.launch.x + plotW * 0.02, cp.ascent.y + plotH * 0.15,
    cp.ascent.x, cp.ascent.y
  )
  ctx.quadraticCurveTo(
    cp.maxq.x - plotW * 0.02, cp.maxq.y + plotH * 0.05,
    cp.maxq.x, cp.maxq.y
  )
  ctx.quadraticCurveTo(
    (cp.maxq.x + cp.meco.x) / 2, cp.meco.y + plotH * 0.02,
    cp.meco.x, cp.meco.y
  )
  ctx.quadraticCurveTo(
    (cp.meco.x + cp.sep.x) / 2, cp.sep.y,
    cp.sep.x, cp.sep.y
  )
  ctx.stroke()

  // 主线
  ctx.strokeStyle = C.trail
  ctx.lineWidth = 2.5 * dpr
  ctx.beginPath()
  ctx.moveTo(cp.launch.x, cp.launch.y)
  ctx.quadraticCurveTo(
    cp.launch.x + plotW * 0.02, cp.ascent.y + plotH * 0.15,
    cp.ascent.x, cp.ascent.y
  )
  ctx.quadraticCurveTo(
    cp.maxq.x - plotW * 0.02, cp.maxq.y + plotH * 0.05,
    cp.maxq.x, cp.maxq.y
  )
  ctx.quadraticCurveTo(
    (cp.maxq.x + cp.meco.x) / 2, cp.meco.y + plotH * 0.02,
    cp.meco.x, cp.meco.y
  )
  ctx.quadraticCurveTo(
    (cp.meco.x + cp.sep.x) / 2, cp.sep.y,
    cp.sep.x, cp.sep.y
  )
  ctx.stroke()

  // ===== 二级弧线（级间分离→整流罩→SECO→部署）=====
  ctx.strokeStyle = C.trail
  ctx.lineWidth = 2 * dpr
  ctx.beginPath()
  ctx.moveTo(cp.sep.x, cp.sep.y)
  ctx.quadraticCurveTo(
    cp.flip.x, cp.flip.y - plotH * 0.01,
    cp.fairing.x, cp.fairing.y
  )
  ctx.quadraticCurveTo(
    (cp.fairing.x + cp.s2coast.x) / 2, cp.s2coast.y - plotH * 0.005,
    cp.s2coast.x, cp.s2coast.y
  )
  ctx.quadraticCurveTo(
    (cp.s2coast.x + cp.seco.x) / 2, cp.seco.y,
    cp.seco.x, cp.seco.y
  )
  ctx.lineTo(cp.deploy.x, cp.deploy.y)
  ctx.stroke()

  // ===== 一级返回弧线（级间分离→翻转→栅格翼→再入→着陆）=====
  if (hasLanding) {
    // 发光
    ctx.strokeStyle = 'rgba(255,255,255,0.08)'
    ctx.lineWidth = 5 * dpr
    ctx.beginPath()
    ctx.moveTo(cp.sep.x, cp.sep.y)
    ctx.quadraticCurveTo(
      cp.gridFins.x - plotW * 0.04, cp.gridFins.y - plotH * 0.05,
      cp.gridFins.x, cp.gridFins.y
    )
    ctx.quadraticCurveTo(
      cp.entry.x, cp.entry.y - plotH * 0.03,
      cp.entry.x, cp.entry.y
    )
    ctx.quadraticCurveTo(
      cp.aero.x - plotW * 0.02, cp.aero.y,
      cp.aero.x, cp.aero.y
    )
    ctx.quadraticCurveTo(
      cp.landing.x - plotW * 0.02, cp.landing.y - plotH * 0.1,
      cp.landing.x, cp.landing.y
    )
    ctx.lineTo(cp.landed.x, cp.landed.y)
    ctx.stroke()

    // 虚线
    ctx.strokeStyle = C.boosterTrail
    ctx.lineWidth = 1.5 * dpr
    ctx.setLineDash([6 * dpr, 4 * dpr])
    ctx.beginPath()
    ctx.moveTo(cp.sep.x, cp.sep.y)
    ctx.quadraticCurveTo(
      cp.gridFins.x - plotW * 0.04, cp.gridFins.y - plotH * 0.05,
      cp.gridFins.x, cp.gridFins.y
    )
    ctx.quadraticCurveTo(
      cp.entry.x, cp.entry.y - plotH * 0.03,
      cp.entry.x, cp.entry.y
    )
    ctx.quadraticCurveTo(
      cp.aero.x - plotW * 0.02, cp.aero.y,
      cp.aero.x, cp.aero.y
    )
    ctx.quadraticCurveTo(
      cp.landing.x - plotW * 0.02, cp.landing.y - plotH * 0.1,
      cp.landing.x, cp.landing.y
    )
    ctx.lineTo(cp.landed.x, cp.landed.y)
    ctx.stroke()
    ctx.setLineDash([])
  }

  // ===== 整流罩分离小弧线 =====
  const fairL = toCanvas({ x: pts.fairing.x - 0.01, y: pts.fairing.y + 0.15 })
  const fairR = toCanvas({ x: pts.fairing.x + 0.03, y: pts.fairing.y + 0.18 })
  ctx.strokeStyle = C.fairing
  ctx.lineWidth = 1 * dpr
  ctx.setLineDash([3 * dpr, 3 * dpr])
  ctx.beginPath()
  ctx.moveTo(cp.fairing.x, cp.fairing.y)
  ctx.quadraticCurveTo(fairL.x, fairL.y, fairL.x - plotW * 0.02, fairL.y + plotH * 0.08)
  ctx.stroke()
  ctx.beginPath()
  ctx.moveTo(cp.fairing.x, cp.fairing.y)
  ctx.quadraticCurveTo(fairR.x, fairR.y, fairR.x + plotW * 0.01, fairR.y + plotH * 0.08)
  ctx.stroke()
  ctx.setLineDash([])

  // ===== 发射火焰效果 =====
  const flameGrad = ctx.createRadialGradient(
    cp.launch.x, cp.launch.y, 0,
    cp.launch.x, cp.launch.y, 20 * dpr
  )
  flameGrad.addColorStop(0, C.flame)
  flameGrad.addColorStop(0.4, C.flameGlow)
  flameGrad.addColorStop(1, 'transparent')
  ctx.fillStyle = flameGrad
  ctx.beginPath()
  ctx.arc(cp.launch.x, cp.launch.y, 20 * dpr, 0, Math.PI * 2)
  ctx.fill()

  // ===== 着陆火焰效果 =====
  if (hasLanding) {
    const landFlame = ctx.createRadialGradient(
      cp.landed.x, cp.landed.y, 0,
      cp.landed.x, cp.landed.y, 12 * dpr
    )
    landFlame.addColorStop(0, 'rgba(255,107,53,0.6)')
    landFlame.addColorStop(0.5, 'rgba(255,107,53,0.15)')
    landFlame.addColorStop(1, 'transparent')
    ctx.fillStyle = landFlame
    ctx.beginPath()
    ctx.arc(cp.landed.x, cp.landed.y, 12 * dpr, 0, Math.PI * 2)
    ctx.fill()
  }

  // ===== 事件节点 + 标签 =====
  const fontSize = 9 * dpr
  const subFontSize = 7.5 * dpr

  const labelDefs = [
    { key: 'launch', pt: cp.launch, label: 'LAUNCH', sub: '发射', align: 'left', offsetX: 12, offsetY: -10 },
    { key: 'ascent', pt: cp.ascent, label: 'ASCENT', sub: '上升段', align: 'left', offsetX: -45, offsetY: 8 },
    { key: 'maxq', pt: cp.maxq, label: 'MAX-Q', sub: eventMap.maxq ? `T+${Math.round(eventMap.maxq)}s` : '', align: 'left', offsetX: -50, offsetY: 5 },
    { key: 'sep', pt: cp.sep, label: 'STAGE SEPARATION', sub: '级间分离', align: 'center', offsetX: 0, offsetY: -16 },
    { key: 'flip', pt: cp.flip, label: 'FLIP MANEUVER', sub: '翻转机动', align: 'center', offsetX: 0, offsetY: -16 },
    { key: 'fairing', pt: cp.fairing, label: 'FAIRING SEPARATION', sub: '整流罩分离', align: 'right', offsetX: 10, offsetY: -16 },
    { key: 'seco', pt: cp.seco, label: 'SECO', sub: eventMap.seco ? `T+${Math.round(eventMap.seco)}s` : '二级关机', align: 'center', offsetX: 0, offsetY: -14 },
    { key: 'deploy', pt: cp.deploy, label: 'DEPLOY', sub: '载荷部署', align: 'right', offsetX: 0, offsetY: -14 }
  ]

  if (hasLanding) {
    labelDefs.push(
      { key: 'gridFins', pt: cp.gridFins, label: 'GRID FINS DEPLOY', sub: '栅格翼展开', align: 'right', offsetX: 10, offsetY: 5 },
      { key: 'entry', pt: cp.entry, label: 'ENTRY BURN', sub: '再入点火', align: 'right', offsetX: 10, offsetY: 5 },
      { key: 'aero', pt: cp.aero, label: 'AERODYNAMIC GUIDANCE', sub: '气动制导', align: 'right', offsetX: 10, offsetY: 5 },
      { key: 'landed', pt: cp.landed, label: landingType === 'RTLS' ? 'LANDING' : 'DRONESHIP LANDING', sub: landingType === 'RTLS' ? '陆地着陆' : '海上着陆', align: 'right', offsetX: 10, offsetY: -10 }
    )
  }

  for (const def of labelDefs) {
    const { pt, label, sub, align, offsetX, offsetY } = def

    // 节点圆点
    ctx.fillStyle = C.dotGlow
    ctx.beginPath()
    ctx.arc(pt.x, pt.y, 5 * dpr, 0, Math.PI * 2)
    ctx.fill()
    ctx.fillStyle = C.dot
    ctx.beginPath()
    ctx.arc(pt.x, pt.y, 2.5 * dpr, 0, Math.PI * 2)
    ctx.fill()

    // 标签
    const lx = pt.x + offsetX * dpr
    const ly = pt.y + offsetY * dpr
    ctx.textAlign = align === 'right' ? 'left' : (align === 'left' ? 'right' : 'center')
    ctx.textBaseline = 'bottom'

    ctx.font = `bold ${fontSize}px -apple-system, sans-serif`
    ctx.fillStyle = C.label
    ctx.fillText(label, lx, ly)

    if (sub) {
      ctx.font = `${subFontSize}px -apple-system, sans-serif`
      ctx.fillStyle = C.sublabel
      ctx.fillText(sub, lx, ly + subFontSize + 2 * dpr)
    }
  }

  return true
}

/**
 * 从遥测数据中提取关键指标摘要
 */
function extractTelemetrySummary(telemetryData) {
  if (!telemetryData) return null

  const raw = telemetryData.analysed || telemetryData.raw || []
  const stageData = Array.isArray(raw) ? raw[0] : raw
  const points = (stageData && stageData.telemetry) || []
  const events = telemetryData.events || []

  if (points.length === 0) return null

  let maxVelocity = 0, maxAltitude = 0, maxAcceleration = 0
  let totalDuration = 0

  for (const p of points) {
    if (p.velocity > maxVelocity) maxVelocity = p.velocity
    if (p.altitude > maxAltitude) maxAltitude = p.altitude
    if (p.acceleration != null && Math.abs(p.acceleration) > maxAcceleration) {
      maxAcceleration = Math.abs(p.acceleration)
    }
    if (p.time > totalDuration) totalDuration = p.time
  }

  // 提取关键事件时间
  const eventMap = {}
  for (const evt of events) {
    if (evt.time != null) eventMap[evt.key] = evt.time
  }

  return {
    maxVelocity: Math.round(maxVelocity),
    maxVelocityKmh: Math.round(maxVelocity * 3.6),
    maxAltitude: Math.round(maxAltitude),
    maxAcceleration: maxAcceleration ? maxAcceleration.toFixed(1) : null,
    totalDuration: Math.round(totalDuration),
    totalDurationText: totalDuration >= 60
      ? `${Math.floor(totalDuration / 60)}分${Math.round(totalDuration % 60)}秒`
      : `${Math.round(totalDuration)}秒`,
    mecoTime: eventMap.meco ? `T+${Math.round(eventMap.meco)}s` : null,
    maxqTime: eventMap.maxq ? `T+${Math.round(eventMap.maxq)}s` : null,
    dataPoints: points.length,
    events: events.filter(e => e.time != null).map(e => ({
      key: e.key,
      label: EVENT_LABELS[e.key] || e.key,
      time: e.time,
      timeText: `T+${Math.round(e.time)}s`
    })),
    stageName: stageData && stageData.stage != null ? `第${stageData.stage}级` : ''
  }
}

module.exports = {
  drawTelemetryChart,
  drawFlightProfile,
  extractTelemetrySummary
}
